mapper.update:
update post
set post_likes = post_likes +1
where post_idx=#{post_idx}

mapper.delete:
delete from recommend
from recommend
where member_idx = #{member_idx} and post_idx=#{post_idx}

mapper.update:
update post
set post_likes = post_likes - 1
where post_idx = #{post_idx}

mapper.select:
SELECT p.*,
(p.post_likes * 3 + p.post_views * 1 - TIMESTAMPDIFF(DAY, p.post_created_at, NOW()) * 2
) AS popularity
FROM post p
ORDER BY popularity DESC
LIMIT #{offset}, #{pageSize} ;
